9	/// A macro pack (profile) consisting of categorized macros.
10	#[derive(Debug, Clone, Serialize, Deserialize)]
11	pub struct Pack {
12	    /// Display name of the pack, also used as the profiles directory entry name.
13	    pub name: String,
14	    /// Optional author attribution stored in `pack.yaml`.
15	    pub author: Option<String>,
16	    /// Ordered list of macro categories; macros are flattened for matching.
17	    pub categories: Vec<Category>,
18	}
19	
20	/// A named grouping of macros.
21	#[derive(Debug, Clone, Serialize, Deserialize)]
22	pub struct Category {
23	    /// Display name for this category (e.g. `"Stratagems"`).
24	    pub name: String,
25	    /// Macros belonging to this category.
26	    pub macros: Vec<MacroConfig>,
27	}
28	
29	impl Pack {
30	    /// Flatten the categories into a single list of macros.
31	    pub fn flatten(&self) -> Vec<MacroConfig> {
32	        self.categories
33	            .iter()
34	            .flat_map(|c| c.macros.clone())
35	            .collect()
36	    }
37	
38	    /// Load a pack from a directory containing `pack.yaml`.
39	    pub fn load_from_dir(dir: &Path) -> Result<Self> {
40	        let yaml_path = dir.join("pack.yaml");
41	        let file = std::fs::File::open(&yaml_path)
42	            .with_context(|| format!("Failed to open pack.yaml at {}", yaml_path.display()))?;
43	        let pack: Pack = serde_yaml_ng::from_reader(file)
44	            .with_context(|| format!("Failed to parse pack.yaml at {}", yaml_path.display()))?;
45	        Ok(pack)
46	    }
47	
48	    /// Save the pack to a directory as `pack.yaml`.
49	    pub fn save_to_dir(&self, dir: &Path) -> Result<()> {
50	        let yaml_path = dir.join("pack.yaml");
51	        let file = std::fs::File::create(&yaml_path)
52	            .with_context(|| format!("Failed to create pack.yaml at {}", yaml_path.display()))?;
53	        serde_yaml_ng::to_writer(file, self)
54	            .with_context(|| format!("Failed to serialize pack.yaml to {}", yaml_path.display()))?;
55	        Ok(())
56	    }
57	
58	    /// Import a .hdpack (ZIP) file.
59	    pub fn import(zip_path: &Path) -> Result<Self> {
60	        let file = std::fs::File::open(zip_path)?;
61	        let mut archive = zip::ZipArchive::new(file)?;
62	        
63	        // Find pack.yaml to get the pack name
64	        let mut pack_yaml_content = String::new();
65	        {
66	            let mut file = archive.by_name("pack.yaml")
67	                .context("ZIP archive missing pack.yaml")?;
68	            use std::io::Read;
69	            file.read_to_string(&mut pack_yaml_content)?;
70	        }
71	        
72	        let pack: Pack = serde_yaml_ng::from_str(&pack_yaml_content)
73	            .context("Failed to parse pack.yaml from ZIP")?;
74	        
75	        let dest_dir = get_profiles_dir()?.join(&pack.name);
76	        if dest_dir.exists() {
77	            std::fs::remove_dir_all(&dest_dir)?;
78	        }
79	        std::fs::create_dir_all(&dest_dir)?;
80	
81	        // Extract all files with path traversal protection
82	        for i in 0..archive.len() {
83	            let mut file = archive.by_index(i)?;
84	            let outpath = match file.enclosed_name() {
85	                Some(path) => dest_dir.join(path),
86	                None => continue,
87	            };
88	
89	            if (*file.name()).ends_with('/') {
90	                std::fs::create_dir_all(&outpath)?;
91	            } else {
92	                if let Some(p) = outpath.parent() {
93	                    if !p.exists() {
94	                        std::fs::create_dir_all(p)?;
95	                    }
96	                }
97	                let mut outfile = std::fs::File::create(&outpath)?;
98	                std::io::copy(&mut file, &mut outfile)?;
99	            }
100	        }
101	
102	        Ok(pack)
103	    }
104	
105	    /// Export a pack to a .hdpack (ZIP) file.
106	    pub fn export(&self, source_dir: &Path, dest_path: &Path) -> Result<()> {
107	        let file = std::fs::File::create(dest_path)?;
108	        let mut zip = zip::ZipWriter::new(file);
109	        let options = zip::write::FileOptions::default()
110	            .compression_method(zip::CompressionMethod::Stored);
111	
112	        // Write pack.yaml
113	        zip.start_file("pack.yaml", options)?;
114	        let yaml = serde_yaml_ng::to_string(self)?;
115	        use std::io::Write;
116	        zip.write_all(yaml.as_bytes())?;
117	
118	        // Copy sounds/ directory if it exists in the profile dir
119	        let sounds_dir = source_dir.join("sounds");
120	        if sounds_dir.exists() && sounds_dir.is_dir() {
121	            Self::add_dir_to_zip(&mut zip, &sounds_dir, Path::new("sounds"), options)?;
122	        }
123	        
124	        zip.finish()?;
125	        Ok(())
126	    }
127	
128	    fn add_dir_to_zip<W: std::io::Write + std::io::Seek>(
129	        zip: &mut zip::ZipWriter<W>,
130	        real_path: &Path,
131	        zip_path: &Path,
132	        options: zip::write::FileOptions,
133	    ) -> Result<()> {
134	        for entry in std::fs::read_dir(real_path)? {
135	            let entry = entry?;
136	            let path = entry.path();
137	            let name = entry.file_name();
138	            let new_zip_path = zip_path.join(name);
139	
140	            if path.is_dir() {
141	                // ZIP directories must end with /
142	                let mut dir_name = new_zip_path.to_string_lossy().into_owned();
143	                if !dir_name.ends_with('/') {
144	                    dir_name.push('/');
145	                }
146	                zip.add_directory(dir_name, options)?;
147	                Self::add_dir_to_zip(zip, &path, &new_zip_path, options)?;
148	            } else {
149	                zip.start_file(new_zip_path.to_string_lossy(), options)?;
150	                let mut f = std::fs::File::open(path)?;
151	                std::io::copy(&mut f, zip)?;
152	            }
153	        }
154	        Ok(())
155	    }
156	}
