331	    // import() extracts to XDG_CONFIG_HOME/vibe-attack/profiles/<name>.
332	    // We redirect XDG_CONFIG_HOME to a second temp dir to stay hermetic.
333	    let source_dir = tempfile::tempdir().unwrap();
334	    let import_root = tempfile::tempdir().unwrap();
335	
336	    let pack = Pack {
337	        name: "ImportTest".to_string(),
338	        author: Some("tester".to_string()),
339	        categories: vec![Category {
340	            name: "Test".to_string(),
341	            macros: vec![macro_simple(
342	                "Reinforce",
343	                "reinforce",
344	                vec![key("KEY_W"), key("KEY_S")],
