350	    let zip_path = source_dir.path().join("importtest.hdpack");
351	    pack.export(source_dir.path(), &zip_path).unwrap();
352	
353	    // Redirect XDG so import() writes into our temp dir, not the real config home.
354	    std::env::set_var("XDG_CONFIG_HOME", import_root.path());
355	    let imported = Pack::import(&zip_path).expect("import must succeed");
356	    std::env::remove_var("XDG_CONFIG_HOME");
